"use client";

import InfiniteGridGallery from "./InfiniteGridGallery";

export default InfiniteGridGallery;

export default class InfiniteGrid {
 constructor({ el, sources, data, originalSize, onItemClick }) {
 this.$container = el;
 this.sources = sources;
 this.data = data;
 this.originalSize = originalSize;
 this.onItemClick = onItemClick;
 this.enabled = true;

 // Fixed grid layout (non-overlapping) like the reference.
 this.layout = {
 cols: 4,
 rows: 3,
 gap: 44,
 margin: 40,
 aspect: 3 / 4, // height = width * aspect (4:3 card)
 };

 this.scroll = {
 ease: 0.1,
 current:{ x: 0, y: 0 },
 target: { x: 0, y: 0 },
 last: { x: 0, y: 0 },
 delta: { x: { c: 0, t: 0 }, y: { c: 0, t: 0 } }
 };

 this.isDragging = false;
 this.drag = { startX: 0, startY: 0, scrollX: 0, scrollY: 0 };
 this.dragMoved = false;

 this.mouse = {
 x: { t: 0.5, c: 0.5 },
 y: { t: 0.5, c: 0.5 },
 press: { t: 0, c: 0 },
 };

 this.items = [];

 this.onResize = this.onResize.bind(this);
 this.onWheel = this.onWheel.bind(this);
 this.onMouseMove = this.onMouseMove.bind(this);
 this.onMouseDown = this.onMouseDown.bind(this);
 this.onMouseUp = this.onMouseUp.bind(this);
 this.render = this.render.bind(this);

 window.addEventListener('resize', this.onResize);
 window.addEventListener('wheel', this.onWheel, { passive: false });
 window.addEventListener('mousemove', this.onMouseMove);
 this.$container.addEventListener('mousedown', this.onMouseDown);
 window.addEventListener('mouseup', this.onMouseUp);

 this.onResize();
 this.render();
 }

 onResize() {
 this.winW = window.innerWidth;
 this.winH = window.innerHeight;

 const cols = this.layout.cols;
 const rows = this.layout.rows;
 const gap = this.layout.gap;
 const margin = this.layout.margin;

 // Keep tiles fitting the viewport so we never visually"eat" the gaps.
 const tileW =
 (this.winW - margin * 2 - gap * (cols - 1)) / cols;
 const tileH = tileW * this.layout.aspect;
 const halfGap = gap / 2;

 // Effective outer size per tile includes the gap padding on both sides.
 const outerW = tileW + gap;
 const outerH = tileH + gap;

 // Total set size across the visible grid (outer tiles abut each other).
 const setW = cols * outerW;
 const setH = rows * outerH;

 // Center the grid vertically if there's extra space.
 const topOffset = Math.max(margin, (this.winH - setH) / 2);
 const leftOffset = Math.max(margin, (this.winW - setW) / 2);

 this.tileSize = { w: setW, h: setH, tileW, tileH, gap, halfGap, leftOffset, topOffset };

 this.scroll.current = { x: 0, y: 0 };
 this.scroll.target = { x: 0, y: 0 };
 this.scroll.last = { x: 0, y: 0 };

 this.$container.innerHTML ='';

 const baseItems = [];
 const total = cols * rows;

 for (let i = 0; i < total; i++) {
 const col = i % cols;
 const row = Math.floor(i / cols);
 const source = this.sources[i % this.sources.length];

 baseItems.push({
 src: source.src,
 caption: source.caption,
 sourceIndex: i % this.sources.length,
 x: leftOffset + col * outerW,
 y: topOffset + row * outerH,
 w: tileW,
 h: tileH,
 });
 }

 this.items = [];
 const repsX = [0, this.tileSize.w];
 const repsY = [0, this.tileSize.h];

 baseItems.forEach(base => {
 repsX.forEach(offsetX => {
 repsY.forEach(offsetY => {
 const el = document.createElement('div');
 el.classList.add('item');
 // Add internal padding so gaps stay visually consistent even with borders/hover.
 el.style.padding = `${this.tileSize.halfGap}px`;
 el.style.width = `${base.w + this.tileSize.gap}px`;
 el.style.height = `${base.h + this.tileSize.gap}px`;

 const wrapper = document.createElement('div');
 wrapper.classList.add('item-wrapper');
 el.appendChild(wrapper);

 const itemImage = document.createElement('div');
 itemImage.classList.add('item-image');
 itemImage.style.width = `${base.w}px`;
 itemImage.style.height = `${base.h}px`;
 wrapper.appendChild(itemImage);

 const img = new Image();
 img.loading ='lazy';
 img.decoding ='async';
 img.referrerPolicy ='no-referrer';
 img.src = base.src;
 img.alt = base.caption;
 itemImage.appendChild(img);

 const caption = document.createElement('small');
 caption.classList.add('caption');
 caption.textContent = base.caption;
 wrapper.appendChild(caption);

 if (typeof this.onItemClick ==='function') {
 el.style.cursor ='pointer';
 el.addEventListener('click', (event) => {
 // Ignore clicks when the user was dragging.
 if (this.isDragging || this.dragMoved) return;
 event.stopPropagation();
 const rect = itemImage.getBoundingClientRect();
 this.onItemClick({
 index: base.sourceIndex,
 src: base.src,
 caption: base.caption,
 rect: {
 left: rect.left,
 top: rect.top,
 width: rect.width,
 height: rect.height,
 },
 });
 });
 }

 this.$container.appendChild(el);

 this.items.push({
 el,
 container: itemImage,
 wrapper,
 img,
 x: base.x + offsetX,
 y: base.y + offsetY,
 w: base.w,
 h: base.h,
 extraX: 0,
 extraY: 0,
 rect: el.getBoundingClientRect(),
 ease: Math.random() * 0.5 + 0.5,
 depth: Math.random() * 0.75 + 0.25,
 });
 });
 });
 });

 // The repeated grid spans 2x in each axis (we created copies at +setW/+setH).
 // Wrapping by the full 2-set span prevents the duplicates from collapsing
 // onto each other (which can visually eliminate gaps).
 this.wrapSize = { w: this.tileSize.w * 2, h: this.tileSize.h * 2 };

 this.scroll.current.x = this.scroll.target.x = this.scroll.last.x = -this.winW * 0.1;
 this.scroll.current.y = this.scroll.target.y = this.scroll.last.y = -this.winH * 0.1;
 }

 onWheel(e) {
 if (!this.enabled) return;
 e.preventDefault();
 const factor = 0.9;
 this.scroll.target.x -= e.deltaX * factor;
 this.scroll.target.y -= e.deltaY * factor;
 }

 onMouseDown(e) {
 if (!this.enabled) return;
 e.preventDefault();
 this.isDragging = true;
 this.dragMoved = false;
 document.documentElement.classList.add('dragging');
 this.mouse.press.t = 1;
 this.drag.startX = e.clientX;
 this.drag.startY = e.clientY;
 this.drag.scrollX = this.scroll.target.x;
 this.drag.scrollY = this.scroll.target.y;
 }

 onMouseUp() {
 this.isDragging = false;
 document.documentElement.classList.remove('dragging');
 this.mouse.press.t = 0;
 }

 onMouseMove(e) {
 if (!this.enabled) return;
 this.mouse.x.t = e.clientX / this.winW;
 this.mouse.y.t = e.clientY / this.winH;

 if (this.isDragging) {
 const dx = e.clientX - this.drag.startX;
 const dy = e.clientY - this.drag.startY;
 if (!this.dragMoved && (Math.abs(dx) > 3 || Math.abs(dy) > 3)) {
 this.dragMoved = true;
 }
 this.scroll.target.x = this.drag.scrollX + dx;
 this.scroll.target.y = this.drag.scrollY + dy;
 }
 }

 render() {
 this.scroll.current.x += (this.scroll.target.x - this.scroll.current.x) * this.scroll.ease;
 this.scroll.current.y += (this.scroll.target.y - this.scroll.current.y) * this.scroll.ease;

 this.scroll.delta.x.t = this.scroll.current.x - this.scroll.last.x;
 this.scroll.delta.y.t = this.scroll.current.y - this.scroll.last.y;
 this.scroll.delta.x.c += (this.scroll.delta.x.t - this.scroll.delta.x.c) * 0.04;
 this.scroll.delta.y.c += (this.scroll.delta.y.t - this.scroll.delta.y.c) * 0.04;
 this.mouse.x.c += (this.mouse.x.t - this.mouse.x.c) * 0.04;
 this.mouse.y.c += (this.mouse.y.t - this.mouse.y.c) * 0.04;
 this.mouse.press.c += (this.mouse.press.t - this.mouse.press.c) * 0.04;

 const dirX = this.scroll.current.x > this.scroll.last.x ?'right' :'left';
 const dirY = this.scroll.current.y > this.scroll.last.y ?'down' :'up';

 this.items.forEach(item => {
 // No parallax: keep tiles rigid in the grid.
 const newX = 0;
 const newY = 0;
 const scrollX = this.scroll.current.x;
 const scrollY = this.scroll.current.y;
 const posX = item.x + scrollX + item.extraX + newX;
 const posY = item.y + scrollY + item.extraY + newY;

 const beforeX = posX > this.winW;
 const afterX = posX + item.rect.width < 0;
 if (dirX ==='right' && beforeX) item.extraX -= this.wrapSize.w;
 if (dirX ==='left' && afterX) item.extraX += this.wrapSize.w;

 const beforeY = posY > this.winH;
 const afterY = posY + item.rect.height < 0;
 if (dirY ==='down' && beforeY) item.extraY -= this.wrapSize.h;
 if (dirY ==='up' && afterY) item.extraY += this.wrapSize.h;

 const fx = item.x + scrollX + item.extraX + newX;
 const fy = item.y + scrollY + item.extraY + newY;
 item.el.style.transform = `translate(${fx}px, ${fy}px)`;

 // No parallax (keep a tiny scale for coverage).
 item.img.style.transform = `translate(0px, 0px) scale(1.04)`;
 });

 this.scroll.last.x = this.scroll.current.x;
 this.scroll.last.y = this.scroll.current.y;

 requestAnimationFrame(this.render);
 }

 destroy() {
 window.removeEventListener('resize', this.onResize);
 window.removeEventListener('wheel', this.onWheel);
 window.removeEventListener('mousemove', this.onMouseMove);
 this.$container.removeEventListener('mousedown', this.onMouseDown);
 window.removeEventListener('mouseup', this.onMouseUp);
 }

 setEnabled(next) {
 this.enabled = Boolean(next);
 if (!this.enabled) {
 this.isDragging = false;
 this.dragMoved = false;
 this.mouse.press.t = 0;
 document.documentElement.classList.remove('dragging');
 }
 }
}

"use client";

import { useEffect, useMemo, useRef, useState } from"react";
import InfiniteGrid from"./InfiniteGrid";
import styles from"./InfiniteGridGallery.module.css";

export default function InfiniteGridGallery() {
 const imagesRef = useRef(null);
 const gridRef = useRef(null);

 const expandThumbsRef = useRef(null);
 const expandThumbRefs = useRef([]);
 const thumbClickIndexRef = useRef(null);

 const thumbDragRef = useRef({
 active: false,
 pointerId: null,
 startX: 0,
 startScrollLeft: 0,
 moved: false,
 });

 const [expanded, setExpanded] = useState(null);
 const [isClosing, setIsClosing] = useState(false);
 const [isOpening, setIsOpening] = useState(false);
 const [displayIndex, setDisplayIndex] = useState(null);
 const [slide, setSlide] = useState(null);
 const [isThumbDragging, setIsThumbDragging] = useState(false);

 const closeTimerRef = useRef(null);
 const slideTimerRef = useRef(null);

 const slideDurationMs = 600;
 const openCloseDurationMs = 750;
 const isAnimating = isOpening || isClosing || Boolean(slide);

 const overlayLayout = useMemo(() => ({ thumbsH: 156 }), []);

 const unsplashPool = useMemo(
 () => [
 {
 src:"/assets/gradient/image1.png",
 title:"Velora Drift",
 },
 {
 src:"/assets/gradient/image12.png",
 title:"Zentha Bloom",
 },
 {
 src:"/assets/gradient/image3.png",
 title:"Auralis Fade",
 },
 {
 src:"/assets/gradient/image14.png",
 title:"Nyxara Flow",
 },
 {
 src:"/assets/gradient/image5.png",
 title:"Solune Mist",
 },
 {
 src:"/assets/gradient/image9.png",
 title:"Cryon Pulse",
 },
 {
 src:"/assets/gradient/image6.png",
 title:"Luneth Glow",
 },
 {
 src:"/assets/gradient/image7.png",
 title:"Virel Shift",
 },
 {
 src:"/assets/gradient/image10.png",
 title:"Orvyn Haze",
 },
 {
 src:"/assets/gradient/image8.png",
 title:"Draxen Veil",
 },
 {
 src:"/assets/gradient/image11.png",
 title:"Kaelis Tone",
 },
 {
 src:"/assets/gradient/image2.png",
 title:"Myra Flux",
 },
 {
 src:"/assets/gradient/image13.png",
 title:"Zypher Blend",
 },
 {
 src:"/assets/gradient/image4.png",
 title:"Elyon Sweep",
 },
 {
 src:"/assets/gradient/image15.png",
 title:"Thyra Wave",
 },
 ],
 []
);

 const sources = useMemo(
 () =>
 Array.from({ length: 120 }, (_, i) => {
 const pick = unsplashPool[i % unsplashPool.length];

 return {
 src: pick.src,
 caption: (() => {
 // Deterministic"random" name per index (stable across reloads).
 const adjectives = [
"Silent",
"Soft",
"Luminous",
"Velvet",
"Electric",
"Drifting",
"Infinite",
"Neon",
"Golden",
"Hidden",
"Crystal",
"Midnight",
"Warm",
"Icy",
"Dusty",
"Liquid",
"Misty",
"Aurora",
"Calm",
"Vivid",
 ];

 const nouns = [
"Horizon",
"Gradient",
"Bloom",
"Echo",
"Field",
"Wave",
"Ridge",
"Atlas",
"Canvas",
"Spectrum",
"Orbit",
"Shoreline",
"Valley",
"Glade",
"Tide",
"Mirage",
"Pulse",
"Drift",
"Skylight",
"Cascade",
 ];

 const a = adjectives[i % adjectives.length];
 const b = nouns[(i * 7) % nouns.length];
 return `${a} ${b}`;
 })(),
 };
 }),
 [unsplashPool]
 );

 const data = useMemo(() => {
 const cols = 3;
 const rows = 3;

 const itemW = 400;
 const itemH = 270;
 const gap = 40;
 const startX = 71;
 const startY = 58;

 return Array.from({ length: cols * rows }, (_, i) => {
 const col = i % cols;
 const row = Math.floor(i / cols);

 return {
 x: startX + col * (itemW + gap),
 y: startY + row * (itemH + gap),
 w: itemW,
 h: itemH,
 };
 });
}, []);

 useEffect(() => {
 const el = imagesRef.current;
 if (!el) return;

 const setRvw = () => {
 document.documentElement.style.setProperty(
"--rvw",
 `${document.documentElement.clientWidth / 100}px`
 );
 };

 setRvw();
 window.addEventListener("resize", setRvw);

 gridRef.current = new InfiniteGrid({
 el,
 sources,
 data,
 originalSize: { w: 1422, h: 1006 },
 onItemClick: ({ index, rect }) => {
 const vw = window.innerWidth;
 const vh = window.innerHeight;
 const thumbsH = overlayLayout.thumbsH;

 const maxH = Math.max(240, vh - thumbsH - 36);
 const targetW = Math.round(vw * 0.7);
 const targetH = Math.round(Math.min(vh * 0.7, maxH * 0.98));

 const targetLeft = Math.round((vw - targetW) / 2);
 const targetTop = Math.round((maxH - targetH) / 2);

 setIsClosing(false);
 setIsOpening(true);
 setExpanded({
 index,
 rect,
 vw,
 vh,
 target: {
 left: targetLeft,
 top: targetTop,
 width: targetW,
 height: targetH,
 },
 thumbsH,
 });
 setDisplayIndex(index);
 setSlide(null);
 },
 });

 return () => {
 window.removeEventListener("resize", setRvw);
 gridRef.current?.destroy?.();
 gridRef.current = null;
 };
 }, [data, sources, overlayLayout.thumbsH]);

 const active = expanded ? sources[expanded.index] : null;
 const display = displayIndex === null ? null : sources[displayIndex];

 const centerActiveThumb = (index, behavior ="smooth") => {
 const container = expandThumbsRef.current;
 const activeThumb = expandThumbRefs.current[index];

 if (!container || !activeThumb) return;

 const left =
 activeThumb.offsetLeft -
 container.clientWidth / 2 +
 activeThumb.clientWidth / 2;

 container.scrollTo({ left, behavior });
 };

 const navigateTo = (nextIndex) => {
 if (!expanded) return;
 if (isAnimating) return;

 if (nextIndex === expanded.index) {
 centerActiveThumb(nextIndex,"smooth");
 return;
 }

 const n = sources.length;
 const currentIndex = expanded.index;
 const forward = (nextIndex - currentIndex + n) % n;
 const backward = (currentIndex - nextIndex + n) % n;
 const dir = forward <= backward ? 1 : -1;

 window.clearTimeout(slideTimerRef.current);

 setSlide({ from: currentIndex, to: nextIndex, dir });
 setExpanded((s) => (!s ? s : { ...s, index: nextIndex }));

 slideTimerRef.current = window.setTimeout(() => {
 setDisplayIndex(nextIndex);
 setSlide(null);
 }, slideDurationMs);
 };

 const closeExpanded = () => {
 if (!expanded || isClosing) return;

 setIsClosing(true);
 setIsOpening(false);
 setSlide(null);

 window.clearTimeout(closeTimerRef.current);
 closeTimerRef.current = window.setTimeout(() => {
 setExpanded(null);
 setIsClosing(false);
 setDisplayIndex(null);
 }, openCloseDurationMs);
 };

 useEffect(() => {
 gridRef.current?.setEnabled?.(!expanded);
 }, [expanded]);

 useEffect(() => {
 if (!expanded) return;

 const id = requestAnimationFrame(() => setIsOpening(false));
 return () => cancelAnimationFrame(id);
 }, [expanded]);

 useEffect(() => {
 if (!expanded) return;

 requestAnimationFrame(() => {
 centerActiveThumb(expanded.index,"smooth");
 });
 }, [expanded?.index]);

 useEffect(() => {
 return () => {
 window.clearTimeout(slideTimerRef.current);
 window.clearTimeout(closeTimerRef.current);
 };
 }, []);

 useEffect(() => {
 if (!expanded) return;

 const onKeyDown = (e) => {
 if (e.key ==="Escape") closeExpanded();

 if (e.key ==="ArrowLeft") {
 navigateTo((expanded.index - 1 + sources.length) % sources.length);
 }

 if (e.key ==="ArrowRight") {
 navigateTo((expanded.index + 1) % sources.length);
 }
 };

 window.addEventListener("keydown", onKeyDown);
 return () => window.removeEventListener("keydown", onKeyDown);
 }, [expanded, sources.length]);

 const onThumbPointerDown = (e) => {
 const container = expandThumbsRef.current;
 if (!container) return;

 const button = e.target.closest("[data-thumb-index]");

 thumbClickIndexRef.current = button
 ? Number(button.getAttribute("data-thumb-index"))
 : null;

 thumbDragRef.current.active = true;
 thumbDragRef.current.pointerId = e.pointerId;
 thumbDragRef.current.startX = e.clientX;
 thumbDragRef.current.startScrollLeft = container.scrollLeft;
 thumbDragRef.current.moved = false;

 setIsThumbDragging(true);
 container.setPointerCapture?.(e.pointerId);
 };

 const onThumbPointerMove = (e) => {
 if (!thumbDragRef.current.active) return;
 if (thumbDragRef.current.pointerId !== e.pointerId) return;

 const container = expandThumbsRef.current;
 if (!container) return;

 const dx = e.clientX - thumbDragRef.current.startX;

 if (!thumbDragRef.current.moved && Math.abs(dx) > 3) {
 thumbDragRef.current.moved = true;
 }

 container.scrollLeft = thumbDragRef.current.startScrollLeft - dx;
 };

 const endThumbDrag = (e) => {
 if (!thumbDragRef.current.active) return;
 if (thumbDragRef.current.pointerId !== e.pointerId) return;

 const container = expandThumbsRef.current;
 container?.releasePointerCapture?.(e.pointerId);

 const clickedIndex = thumbClickIndexRef.current;
 const wasDragged = thumbDragRef.current.moved;

 thumbDragRef.current.active = false;
 thumbDragRef.current.pointerId = null;
 thumbClickIndexRef.current = null;

 setIsThumbDragging(false);

 if (!wasDragged && Number.isInteger(clickedIndex)) {
 navigateTo(clickedIndex);
 }

 window.setTimeout(() => {
 thumbDragRef.current.moved = false;
 }, 0);
 };

 const onThumbWheel = (e) => {
 const container = expandThumbsRef.current;
 if (!container) return;

 e.preventDefault();
 container.scrollLeft += e.deltaX || e.deltaY;
 };

 return (
 <section className={styles.root}>
 <div ref={imagesRef} className={styles.images} />

 {active && expanded && display ? (
 <div
 className={`${styles.expandBackdrop} ${
 isOpening ? styles.expandOpening :""
 } ${isClosing ? styles.expandClosing :""}`}
 role="dialog"
 aria-modal="true"
 onMouseDown={() => closeExpanded()}
 >
 <div
 className={styles.expandStage}
 style={{
"--toX": `${expanded.target.left}px`,
"--toY": `${expanded.target.top}px`,
"--toW": expanded.target.width,
"--toH": expanded.target.height,
"--dx": `${expanded.rect.left - expanded.target.left}px`,
"--dy": `${expanded.rect.top - expanded.target.top}px`,
"--sx": expanded.rect.width / expanded.target.width,
"--sy": expanded.rect.height / expanded.target.height,
"--thumbsH": `${expanded.thumbsH}px`,
 }}
 >
 <div
 className={styles.expandMedia}
 aria-hidden="true"
 onMouseDown={(e) => e.stopPropagation()}
 >
 {slide ? (
 <>
 <img
 className={`${styles.expandImage} ${
 styles.expandImageFrom
 } ${
 slide.dir > 0
 ? styles.expandSlideLeft
 : styles.expandSlideRight
 }`}
 src={sources[slide.from].src}
 alt={sources[slide.from].caption}
 loading="eager"
 decoding="async"
 referrerPolicy="no-referrer"
 />

 <img
 className={`${styles.expandImage} ${styles.expandImageTo} ${
 slide.dir > 0
 ? styles.expandSlideLeft
 : styles.expandSlideRight
 }`}
 src={sources[slide.to].src}
 alt={sources[slide.to].caption}
 loading="eager"
 decoding="async"
 referrerPolicy="no-referrer"
 />
 </>
 ) : (
 <img
 className={styles.expandImage}
 src={display.src}
 alt={display.caption}
 loading="eager"
 decoding="async"
 referrerPolicy="no-referrer"
 />
 )}
 </div>

 <button
 type="button"
 className={`${styles.expandNav} ${styles.expandNavPrev}`}
 onMouseDown={(e) => e.stopPropagation()}
 onClick={() =>
 navigateTo((expanded.index - 1 + sources.length) % sources.length)
 }
 aria-label="Previous"
 disabled={isAnimating}
 >
 ‹
 </button>

 <button
 type="button"
 className={`${styles.expandNav} ${styles.expandNavNext}`}
 onMouseDown={(e) => e.stopPropagation()}
 onClick={() => navigateTo((expanded.index + 1) % sources.length)}
 aria-label="Next"
 disabled={isAnimating}
 >
 ›
 </button>

 <div
 className={styles.expandBottom}
 aria-label="All images"
 onMouseDown={(e) => e.stopPropagation()}
 >
 <div className={styles.expandMeta} aria-hidden="true">
 <h2 className={styles.expandCaption}>{display.caption}</h2>
 </div>
 <div
 className={`${styles.expandThumbsWrap} ${
 isThumbDragging ? styles.expandThumbsWrapDragging :""
 }`}
 onPointerDown={onThumbPointerDown}
 onPointerMove={onThumbPointerMove}
 onPointerUp={endThumbDrag}
 onPointerCancel={endThumbDrag}
 onPointerLeave={endThumbDrag}
 onWheel={onThumbWheel}
 >
 <div
 ref={expandThumbsRef}
 className={styles.expandThumbs}
 role="list"
 aria-label="All images"
 >
 {sources.map((item, idx) => {
 const isActive = idx === expanded.index;

 return (
 <button
 key={`${idx}-${item.src}`}
 type="button"
 role="listitem"
 data-thumb-index={idx}
 className={`${styles.expandThumb} ${
 isActive ? styles.expandThumbActive :""
 }`}
 ref={(el) => {
 expandThumbRefs.current[idx] = el;
 }}
 aria-label={`Open ${item.caption}`}
 >
 <img
 className={styles.expandThumbImg}
 src={item.src}
 alt={item.caption}
 loading="lazy"
 decoding="async"
 referrerPolicy="no-referrer"
 />
 </button>
 );
 })}
 </div>
 </div>
 </div>
 </div>
 </div>
 ) : null}
 </section>
 );
}

const isTouch = () => {
 try {
 document.createEvent('TouchEvent');
 return true;
 } catch (e) {
 return false;
 }
}
export default {
 isTouch: isTouch,
}

.root {
  width: 100%;
  height: 100vh;
  box-sizing: border-box;
  overflow: hidden;
  user-select: none;
  cursor: grab;
  background: #ffffff;
  color: #000000;
  font-family: "Roboto Mono", ui-monospace, SFMono-Regular, Menlo, Monaco,
    Consolas, "Liberation Mono", "Courier New", monospace;
}

:global(html.dragging) .root {
  cursor: grabbing;
}

.images {
  width: 100%;
  height: 100%;
  display: inline-block;
  white-space: nowrap;
  position: relative;
  background: #ffffff;
  overflow: hidden;
}

.images :global(.item) {
  position: absolute;
  top: 0;
  left: 0;
  will-change: transform;
  white-space: normal;
}

.images :global(.item-wrapper) {
  will-change: transform;
  position: relative;
  height: 100%;
  width: 100%;
}

.images :global(.item-image) {
  overflow: hidden;
  border-radius: 0;
  border: 1px solid rgba(0, 0, 0, 0.12);
  background: #ffffff;
  transition: box-shadow 350ms cubic-bezier(0.785, 0.135, 0.15, 0.86),
    transform 350ms cubic-bezier(0.785, 0.135, 0.15, 0.86);
  transform-origin: 50% 50%;
}

.images :global(.item:hover .item-image) {
  box-shadow: 0 18px 60px rgba(0, 0, 0, 0.12);
  transform: scale(1.015);
}

.images :global(.item:hover) {
  z-index: 2;
}

.images :global(.item-image img) {
  width: 100%;
  height: 100%;
  overflow: hidden;
  object-fit: cover;
  will-change: transform;
}

.images :global(.caption) {
  position: absolute;
  width: 100%;
  height: auto;
  left:0;
  right:0;
  bottom: 0;
  display: block;
  padding: 10px 10px;
  font-size: 15px;
  line-height: 1.2;
  letter-spacing: -0.04em;
  opacity: 0;
  white-space: normal;
  user-select: none;
  color: #ffffff;
  background: rgba(255, 255, 255, 0.38);
  backdrop-filter: blur(5px);
  border: 1px solid rgba(0, 0, 0, 0.08);
  transform: translateY(12px);
  transition: opacity 350ms cubic-bezier(0.785, 0.135, 0.15, 0.86),
    transform 350ms cubic-bezier(0.785, 0.135, 0.15, 0.86);
  pointer-events: none;
}

.images :global(.item:hover .caption) {
  opacity: 1;
  transform: translateY(0px);
}

.expandBackdrop {
  position: fixed;
  inset: 0;
  z-index: 60;
  background: rgba(255, 255, 255, 1);
  cursor: default;
  opacity: 0;
  transition: opacity 750ms cubic-bezier(0.785, 0.135, 0.15, 0.86);
}

.expandBackdrop:not(.expandClosing):not(.expandOpening) {
  opacity: 1;
}

.expandClosing {
  opacity: 0;
}

.expandOpening {
  opacity: 0;
}

.expandStage {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
}

.expandMedia {
  position: absolute;
  left: var(--toX);
  top: var(--toY);
  width: calc(var(--toW) * 1px);
  height: calc(var(--toH) * 1px);
  transform-origin: 0 0;
  transform: translate(var(--dx), var(--dy)) scale(var(--sx), var(--sy));
  transition: transform 750ms cubic-bezier(0.785, 0.135, 0.15, 0.86);
  will-change: transform;
  border-radius: 0;
  overflow: hidden;
  background: rgba(0, 0, 0, 0.06);
  /* box-shadow: 0 30px 90px rgba(0, 0, 0, 0.18); */
}

.expandBackdrop:not(.expandClosing):not(.expandOpening) .expandMedia {
  transform: translate(0px, 0px) scale(1, 1);
}

.expandBackdrop.expandClosing .expandMedia {
  transform: translate(var(--dx), var(--dy)) scale(var(--sx), var(--sy));
  transition-duration: 750ms;
}

.expandImage {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.expandImageFrom,
.expandImageTo {
  position: absolute;
  inset: 0;
  will-change: transform, opacity;
  backface-visibility: hidden;
  transform: translate3d(0, 0, 0);
}

.expandSlideLeft.expandImageFrom {
  animation: slideFromLeft 600ms ease-in-out forwards;
}

.expandSlideLeft.expandImageTo {
  animation: slideToLeft 600ms ease-in-out forwards;
}

.expandSlideRight.expandImageFrom {
  animation: slideFromRight 600ms ease-in-out forwards;
}

.expandSlideRight.expandImageTo {
  animation: slideToRight 600ms ease-in-out forwards;
}

@keyframes slideFromLeft {
  from {
    transform: translate3d(0%, 0, 0);
  }
  to {
    transform: translate3d(-100%, 0, 0);
  }
}

@keyframes slideToLeft {
  from {
    transform: translate3d(100%, 0, 0);
  }
  to {
    transform: translate3d(0%, 0, 0);
  }
}

@keyframes slideFromRight {
  from {
    transform: translate3d(0%, 0, 0);
  }
  to {
    transform: translate3d(100%, 0, 0);
  }
}

@keyframes slideToRight {
  from {
    transform: translate3d(-100%, 0, 0);
  }
  to {
    transform: translate3d(0%, 0, 0);
  }
}

.expandBottom {
  position: fixed;
  left: 0;
  right: 0;
  bottom: 0;
  height: var(--thumbsH);
  display: grid;
  grid-template-columns: 1fr;
  align-items: center;
  gap: 12px;
  padding: 0 14px 14px;
  background: rgba(255, 255, 255, 1);
  cursor: default;
}

.expandMeta {
  display: flex;
  align-items: center;
  justify-content: center;
  padding-top: 10px;
}

.expandCaption {
  max-width: min(860px, calc(100vw - 40px));
  text-align: center;
  margin-top: -5%;
  font-size: 30px;
  line-height: 1.1;
  font-weight: 500;
  letter-spacing: -0.05em;
  color: rgba(0, 0, 0, 0.92);
  padding: 6px 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  user-select: none;
}

.expandNav {
  position: fixed;
  top: calc(var(--toY) + (var(--toH) * 1px) / 2);
  transform: translateY(-50%);
  width: 54px;
  height: 54px;
  border-radius: 999px;
  border: 1px solid rgba(0, 0, 0, 0.12);
  background: rgba(255, 255, 255, 0.9);
  color: #000000;
  font-size: 30px;
  line-height: 1;
  display: grid;
  place-items: center;
  cursor: pointer;
  box-shadow: 0 18px 60px rgba(0, 0, 0, 0.12);
  z-index: 4;
}

.expandNav:disabled {
  opacity: 0.35;
  cursor: not-allowed;
}

.expandNavPrev {
  left: max(16px, calc(var(--toX) - 72px));
}

.expandNavNext {
  right: max(16px, calc(100vw - (var(--toX) + var(--toW) * 1px) - 72px));
}

.expandThumbsWrap {
  position: relative;
  width: 100%;
  overflow: hidden;
  user-select: none;
  cursor: grab;
  border-top: 1px solid rgba(0, 0, 0, 0.12);
  padding-top: 12px;
}

.expandThumbsWrapDragging {
  cursor: grabbing;
}

.expandThumbs {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  overflow-y: hidden;
  padding: 0 4px;
  overscroll-behavior-x: contain;
  scrollbar-width: none;
  -ms-overflow-style: none;
  cursor: grab;
  touch-action: pan-x;
  scroll-behavior: smooth;
}

.expandThumbsWrapDragging .expandThumbs {
  cursor: grabbing;
  scroll-behavior: auto;
}

.expandThumbs::-webkit-scrollbar {
  display: none;
}

.expandThumb {
  flex: 0 0 auto;
  width: 90px;
  height: 70px;
  border-radius: 0;
  border: 2px solid transparent;
  background: rgba(0, 0, 0, 0.04);
  padding: 0;
  overflow: hidden;
  cursor: pointer;
  box-sizing: border-box;
  transition: border-color 200ms ease, transform 200ms ease;
}

.expandThumbActive {
  border-color: #000000;
}

.expandThumb:hover {
  transform: translateY(-1px);
  border-color: rgba(0, 0, 0, 0.35);
}

.expandThumbActive:hover {
  border-color: #000000;
}

.expandThumbImg {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  border-radius: 0;
  filter: brightness(0.8);
  transition: filter 300ms cubic-bezier(0.785, 0.135, 0.15, 0.86);
}

.expandThumbActive .expandThumbImg {
  filter: brightness(1.05);
}

@media (max-width: 640px) {
  .expandBottom {
    padding: 0 10px 10px;
  }

  .expandNavPrev {
    left: 12px;
  }

  .expandNavNext {
    right: 12px;
  }

  .expandThumb {
    width: 72px;
    height: 48px;
  }
}
